--liquibase formatted sql
--changeset cmpich:0030-la-insertion-grcz12tu-liftover.sql splitStatements:false

-- Insert GRCz12tu locations for 'la' transgenic-insertion features, produced by
-- UCSC liftOver of their Zv9 coordinates through the assembly chain
-- (Zv9 -> GRCz10 -> GRCz11 -> GRCz12tu; chains danRer7ToDanRer10, danRer10ToDanRer11,
-- danRer11ToGCF_049306965.1). These features had a genomic position only on Zv9
-- (in the generated location table), so this establishes their GRCz12tu placement.
--
-- Restricted to the GENE-VALIDATED set: each insertion is 'is allele of' a single
-- gene, and its lifted position keeps the same relative position within that gene
-- (Zv9 gene span from GCF_000002035.4_Zv9_genomic.gff vs GRCz12tu gene span), either
-- directly (<=5% shift) or under an assembly inversion (strand flip). 3742 features.
--
-- Each new sfcl row:
--   - sfcl_zdb_id          minted with get_id('SFCL')
--   - registered in zdb_active_data BEFORE the sfcl insert (FK sfcl_zdb_id_fk_odc)
--   - sfcl_evidence_code   ZDB-TERM-170419-312 'evidence used in automatic assertion'
--                          (computationally lifted; one of the 3 codes allowed by the
--                          sfcl evidence_code_one_of_three_check constraint)
--   - accession            the GRCz12tu RefSeq accession liftOver emitted (NC_1331xx.1)
-- NOT EXISTS guard keeps it idempotent: features that already have a GRCz12tu row are skipped.

create temp table lifted_la (feature text, chromosome text, accession text, start1 int, end1 int) on commit drop;


create temp table to_insert_la on commit drop as
select get_id('SFCL') as sfcl_zdb_id, feature, chromosome, accession, start1, end1
  from lifted_la l
 where not exists (select 1 from sequence_feature_chromosome_location s
                    where s.sfcl_feature_zdb_id = l.feature and s.sfcl_assembly = 'GRCz12tu');

select sfcl_zdb_id from to_insert_la;

   sfcl_assembly, sfcl_chromosome, sfcl_evidence_code, sfcl_chromosome_reference_accession_number)
select sfcl_zdb_id, feature, start1, end1, 'GRCz12tu', chromosome, 'ZDB-TERM-170419-312', accession
  from to_insert_la;
